Here's a modern MSTest test class covering async success, failure, timeout, and cancellation:

```csharp
[TestClass]
public class DataFetcherTests
{
    // MSTest natively supports async Task test methods — just await directly.
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnHttpError()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // Use [Timeout] in milliseconds to fail tests that hang.
    // Applies to the entire test method including setup.
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new MockHttpMessageHandler("fast", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    // Verify that the method properly observes cancellation tokens.
    [TestMethod]
    public async Task FetchAsync_ThrowsOnCancellation()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new MockHttpMessageHandler("data", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Simulate cancellation after a delay to test mid-flight cancellation.
    [TestMethod]
    public async Task FetchAsync_ThrowsOnMidFlightCancellation()
    {
        using var cts = new CancellationTokenSource();
        var handler = new DelayedHttpMessageHandler(
            TimeSpan.FromSeconds(10), cts.Token);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        cts.CancelAfter(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Test helpers ---

    private class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode)
        {
            _content = content;
            _statusCode = statusCode;
        }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            });
        }
    }

    private class DelayedHttpMessageHandler : HttpMessageHandler
    {
        private readonly TimeSpan _delay;
        private readonly CancellationToken _externalToken;

        public DelayedHttpMessageHandler(
            TimeSpan delay, CancellationToken externalToken)
        {
            _delay = delay;
            _externalToken = externalToken;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            // Link both tokens so either can trigger cancellation
            using var linked = CancellationTokenSource
                .CreateLinkedTokenSource(cancellationToken, _externalToken);
            await Task.Delay(_delay, linked.Token);
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns:**

- **Async tests** — return `async Task` (never `async void`); MSTest awaits them natively
- **`[Timeout(ms)]`** — fails the test if it exceeds the deadline; catches hangs
- **`Assert.ThrowsExceptionAsync<T>`** — the async counterpart for exception assertions
- **`CancellationTokenSource`** — use pre-cancelled tokens for immediate cancellation, `CancelAfter` for mid-flight scenarios
- **Custom `HttpMessageHandler`** — avoids real HTTP calls and lets you control responses, status codes, and delays
